39	async function request<T>(
40	  path: string,
41	  options: RequestInit = {},
42	  session?: Session,
43	): Promise<T> {
44	  const headers: Record<string, string> = {
45	    ...(options.headers as Record<string, string>),
46	  };
47	
48	  if (options.method && ["POST", "PUT", "PATCH"].includes(options.method)) {
49	    headers["Content-Type"] = "application/json";
50	  }
51	
52	  if (session?.agentId) {
53	    headers["X-Bayes-Agent-Id"] = session.agentId;
54	  }
55	
56	  const res = await fetch(`${API_BASE}${path}`, {
57	    ...options,
58	    headers,
59	  });
60	
61	  const body = await res.json();
62	
63	  if (!res.ok) {
64	    const err = body as ApiError;
65	    throw new BayesApiError(
66	      res.status,
67	      err.error?.code ?? "unknown_error",
68	      err.error?.details ?? {},
69	    );
70	  }
71	
72	  return body as T;
73	}
