138	function joinUrlPath(basePath: string, path: string): string {
139	  const normalizedBase = basePath === "/" ? "" : basePath.replace(/\/$/, "");
140	  const normalizedPath = path.startsWith("/") ? path : `/${path}`;
141	  return `${normalizedBase}${normalizedPath}`;
142	}
143	
144	export function getMarketPricesWebSocketUrl(marketId: string): string {
145	  const baseUrl = API_BASE
146	    ? new URL(API_BASE, window.location.origin)
147	    : new URL(window.location.origin);
148	  const socketUrl = new URL(baseUrl.toString());
149	  socketUrl.protocol = socketUrl.protocol === "https:" ? "wss:" : "ws:";
150	  socketUrl.pathname = joinUrlPath(
151	    socketUrl.pathname,
152	    `/ws/markets/${encodeURIComponent(marketId)}/prices`,
153	  );
154	  socketUrl.search = "";
155	  socketUrl.hash = "";
156	  return socketUrl.toString();
157	}
