138	function joinUrlPath(basePath: string, path: string): string {
139	  const normalizedBase = basePath === "/" ? "" : basePath.replace(/\/$/, "");
140	  const normalizedPath = path.startsWith("/") ? path : `/${path}`;
141	  return `${normalizedBase}${normalizedPath}`;
142	}
